// Parse and validate LLM JSON response
const input = $input.first().json;
const device = $('Validate Input').first().json.device;

// Check if Gemini errored (rate limit, auth, etc)
if (input.error) {
  const errorMsg = input.error.message || input.error.errorMessage || String(input.error);

  if (errorMsg.includes('quota') || errorMsg.includes('429') || errorMsg.includes('too many requests')) {
    return [{
      json: {
        error: true,
        message: "The AI service is temporarily overloaded. Please try again in about 30 seconds.",
        device
      }
    }];
  }

  return [{
    json: {
      error: true,
      message: "Something went wrong with the AI service. Please try again later or message Amir.",
      device
    }
  }];
}

// Gemini returns content.parts[0].text
let llmText;
if (input.content && input.content.parts && input.content.parts[0] && input.content.parts[0].text) {
  llmText = input.content.parts[0].text;
} else if (typeof input.text === 'string') {
  llmText = input.text;
} else if (typeof input.content === 'string') {
  llmText = input.content;
} else {
  llmText = JSON.stringify(input);
}

// Strip markdown code fences if present
llmText = llmText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let intent;
try {
  intent = JSON.parse(llmText);
} catch (e) {
  return [{
    json: {
      error: true,
      message: "Sorry, I couldn't understand that request. Try something like: 'download season 3 of Severance'",
      device
    }
  }];
}

if (!intent.title || !intent.mediaType) {
  return [{
    json: {
      error: true,
      message: "Sorry, I couldn't extract a title from your request. Try being more specific.",
      device
    }
  }];
}

if (!['movie', 'tv'].includes(intent.mediaType)) {
  intent.mediaType = 'tv';
}

return [{
  json: {
    title: intent.title,
    mediaType: intent.mediaType,
    seasons: intent.seasons || null,
    isAnime: intent.isAnime === true,
    encodedTitle: encodeURIComponent(intent.title),
    device,
    error: false
  }
}];

// Process detailed Seerr data and generate verbose response
const details = $input.first().json;
const intent = $('Parse LLM Response').first().json;
const matchInfo = $('Pick Best Match').first().json;
const title = details.name || details.title || matchInfo.title;
const mediaType = matchInfo.mediaType;
const tmdbId = matchInfo.tmdbId;
const seerrUrl = 'https://seerr.YOUR_DOMAIN/' + mediaType + '/' + tmdbId;
const mi = details.mediaInfo || {};
const status = mi.status || 1;

// --- MOVIE HANDLING ---
if (mediaType === 'movie') {
  // Check if already available
  if (status === 5) {
    return [{
      json: {
        error: false,
        action: 'respond',
        message: "'" + title + "' is already available on Plex!",
        url: seerrUrl,
        device: intent.device
      }
    }];
  }

  // Check if already requested
  if (status === 2 || status === 3) {
    const requests = mi.requests || [];
    const lastReq = requests[requests.length - 1];
    const reqDate = lastReq ? new Date(lastReq.createdAt).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' }) : 'recently';
    return [{
      json: {
        error: false,
        action: 'respond',
        message: "'" + title + "' was already requested on " + reqDate + ". If the download seems stuck, message Amir.",
        url: seerrUrl,
        device: intent.device
      }
    }];
  }

  // Check if not yet released
  const releaseDate = details.releaseDate;
  const isUnreleased = releaseDate && new Date(releaseDate) > new Date();
  let movieMsg = '';
  if (isUnreleased) {
    const relDateStr = new Date(releaseDate).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });
    movieMsg = "'" + title + "' hasn't been released yet (expected " + relDateStr + "). Requesting it now — it'll download automatically when available.";
  }

  // Build request
  let requestBody = { mediaType: 'movie', mediaId: tmdbId };
  if (intent.isAnime) requestBody.serverId = 2;

  return [{
    json: {
      error: false,
      action: 'request',
      requestBody,
      title,
      successMessage: movieMsg || "Done! '" + title + "' has been requested and should be available soon.",
      url: seerrUrl,
      device: intent.device
    }
  }];
}

// --- TV HANDLING ---
const seasons = details.seasons || [];
const miSeasons = mi.seasons || [];
const requests = mi.requests || [];

// Figure out which seasons the user wants
let wantedSeasons = [];
if (intent.seasons === 'all' || intent.seasons === null) {
  wantedSeasons = seasons.filter(s => s.seasonNumber > 0).map(s => s.seasonNumber);
} else if (Array.isArray(intent.seasons)) {
  wantedSeasons = intent.seasons;
}

// Categorize each wanted season
const available = [];
const pending = [];
const notAired = [];
const toRequest = [];

for (const sNum of wantedSeasons) {
  const seasonInfo = seasons.find(s => s.seasonNumber === sNum);
  const miSeason = miSeasons.find(s => s.seasonNumber === sNum);
  const seasonStatus = miSeason ? miSeason.status : 1;

  // Check if season has aired
  if (seasonInfo && seasonInfo.episodeCount === 0) {
    const airDate = seasonInfo.airDate;
    notAired.push({ num: sNum, airDate });
    continue;
  }

  // Check if already available on Plex
  if (seasonStatus === 5) {
    available.push(sNum);
    continue;
  }

  // Check if already requested/pending
  const existingReq = requests.find(r =>
    r.seasons && r.seasons.some(rs => rs.seasonNumber === sNum && rs.status === 2)
  );
  if (existingReq) {
    const reqDate = new Date(existingReq.createdAt).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });
    pending.push({ num: sNum, date: reqDate });
    continue;
  }

  toRequest.push(sNum);
}

// Build verbose message
let messageParts = [];

if (available.length > 0) {
  messageParts.push("Season" + (available.length > 1 ? "s " : " ") + available.join(', ') + (available.length > 1 ? " are" : " is") + " already available on Plex.");
}

if (pending.length > 0) {
  const pendingNums = pending.map(p => p.num).join(', ');
  const lastDate = pending[pending.length - 1].date;
  messageParts.push("Season" + (pending.length > 1 ? "s " : " ") + pendingNums + " already requested (since " + lastDate + "). If the download seems stuck, message Amir.");
}

if (notAired.length > 0) {
  for (const na of notAired) {
    if (na.airDate) {
      const dateStr = new Date(na.airDate).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });
      messageParts.push("Season " + na.num + " hasn't aired yet — expected " + dateStr + ". It will be automatically downloaded when it airs.");
    } else {
      messageParts.push("Season " + na.num + " hasn't aired yet (no release date announced). It will be automatically downloaded when it airs.");
    }
  }
}

if (toRequest.length > 0) {
  messageParts.push("Requesting season" + (toRequest.length > 1 ? "s " : " ") + toRequest.join(', ') + " now.");
}

// If nothing to request, just respond
if (toRequest.length === 0) {
  return [{
    json: {
      error: false,
      action: 'respond',
      message: "'" + title + "': " + messageParts.join(' '),
      url: seerrUrl,
      device: intent.device
    }
  }];
}

// Build request payload
let requestBody = { mediaType: 'tv', mediaId: tmdbId, seasons: toRequest };
if (intent.isAnime) requestBody.serverId = 2;

const animeText = intent.isAnime ? ' [anime]' : '';

return [{
  json: {
    error: false,
    action: 'request',
    requestBody,
    title,
    successMessage: "'" + title + "': " + messageParts.join(' ') + animeText,
    url: seerrUrl,
    device: intent.device
  }
}];

// Build final success response
const prev = $('Process Results').first().json;
const seerrResponse = $input.first().json;

if (seerrResponse.statusCode && seerrResponse.statusCode >= 400) {
  return [{
    json: {
      success: false,
      message: "Failed to request '" + prev.title + "': " + (seerrResponse.message || 'Seerr returned an error. Message Amir if this keeps happening.'),
      url: prev.url,
      device: prev.device
    }
  }];
}

return [{
  json: {
    success: true,
    message: prev.successMessage,
    url: prev.url,
    device: prev.device
  }
}];

// Pick best matching result from search
const searchData = $input.first().json;
const intent = $('Parse LLM Response').first().json;
const results = searchData.results || [];

if (results.length === 0) {
  return [{
    json: {
      error: true,
      message: "Couldn't find '" + intent.title + "' on Seerr. Check the title and try again.",
      device: intent.device
    }
  }];
}

let match = results.find(r => r.mediaType === intent.mediaType) || results[0];

return [{
  json: {
    tmdbId: match.id,
    mediaType: match.mediaType,
    title: match.name || match.title,
    error: false
  }
}];
